/**
 * Get all categories from the knowledge base
 */
export function getKnowledgeCategories(): string[] {
  const categories = new Set(moeiKnowledgeBase.map(a => a.category))
  return Array.from(categories)
}

/**
 * Search knowledge base by text query
 */
export function searchKnowledgeBase(query: string, limit = 5): KnowledgeArticle[] {
  const lowerQuery = query.toLowerCase()
  const scored = moeiKnowledgeBase.map(article => {
    let score = 0
    const searchFields = [
      article.titleEn.toLowerCase(),
      article.titleAr,
      article.contentEn.toLowerCase(),
      article.contentAr,
      article.category.toLowerCase(),
      article.tags.toLowerCase()
    ]
    for (const field of searchFields) {
      if (field.includes(lowerQuery)) score += 1
    }
    // Boost exact tag matches
    const queryWords = lowerQuery.split(/\s+/)
    const tagWords = article.tags.toLowerCase().split(',')
    for (const qw of queryWords) {
      for (const tw of tagWords) {
        if (tw.trim().includes(qw)) score += 2
      }
    }
    return { article, score }
  })

  return scored
    .filter(s => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map(s => s.article)
}

/**
 * Get articles by category
 */
export function getArticlesByCategory(category: string): KnowledgeArticle[] {
  return moeiKnowledgeBase.filter(a => a.category === category)
}

/**
 * Get article by ID
 */
export function getArticleById(id: string): KnowledgeArticle | undefined {
  return moeiKnowledgeBase.find(a => a.id === id)
}
